"use client";

import { motion, useReducedMotion } from "framer-motion";
import type { TimelineImage } from "../../data/timeline";

interface Props {
  images: TimelineImage[];
  /** 0-1 scroll progress within the active event window */
  progress: number;
}

export default function TimelineBackgroundMedia({ images, progress }: Props) {
  const reducedMotion = useReducedMotion();

  return (
    <div className="absolute inset-0 overflow-hidden" aria-hidden="true">
      {/* Atmospheric base */}
      <div className="absolute inset-0 bg-background" />

      {images.map((img, i) => {
        const y = reducedMotion ? 0 : (progress - 0.5) * img.depth * 120;
        const scale = reducedMotion ? 1 : 1 + img.depth * 0.08;
        const opacity = 0.15 + img.depth * 0.15;

        return (
          <motion.div
            key={img.id}
            className="absolute inset-0"
            style={{ zIndex: i }}
            animate={{ y, scale }}
            transition={{ type: "tween", ease: "linear", duration: 0 }}
          >
            {/* We use a div with background-image so missing files just show nothing */}
            <div
              className="absolute inset-0 bg-cover bg-no-repeat"
              style={{
                backgroundImage: `url(${img.src})`,
                backgroundPosition: img.position ?? "center center",
                opacity,
                filter: "blur(2px) saturate(0.6)",
              }}
            />
          </motion.div>
        );
      })}

      {/* Gradient overlays for readability */}
      <div className="absolute inset-0 bg-gradient-to-r from-background via-background/80 to-background/40 z-10" />
      <div className="absolute inset-0 bg-gradient-to-t from-background via-transparent to-background/60 z-10" />
    </div>
  );
}
