"use client";

import { motion, useReducedMotion } from "framer-motion";
import type { TimelineEvent } from "../../data/timeline";

interface Props {
  event: TimelineEvent;
  isActive: boolean;
}

export default function TimelineEventCard({ event, isActive }: Props) {
  const reducedMotion = useReducedMotion();

  const variants = reducedMotion
    ? { active: { opacity: 1 }, inactive: { opacity: 0.4 } }
    : {
        active: { opacity: 1, y: 0, filter: "blur(0px)" },
        inactive: { opacity: 0.3, y: 12, filter: "blur(2px)" },
      };

  return (
    <motion.article
      className="flex-shrink-0 w-[85vw] md:w-[520px] lg:w-[560px] px-4 md:px-0"
      animate={isActive ? "active" : "inactive"}
      variants={variants}
      transition={{ duration: 0.5, ease: "easeOut" }}
      aria-current={isActive ? "step" : undefined}
    >
      <div className="space-y-6">
        {/* Meta row */}
        <div className="flex items-center gap-3">
          <span className="analytical-label text-accent">{event.category}</span>
          <span className="h-px flex-1 bg-white/10" />
          <span className="coordinate-label">
            {event.location ?? ""}
          </span>
        </div>

        {/* Date */}
        <p className="font-mono text-sm text-accent/70 tracking-widest">
          {event.start}
          {event.end ? ` — ${event.end}` : " — Present"}
        </p>

        {/* Title block */}
        <div>
          <h2 className="text-3xl md:text-4xl lg:text-5xl font-bold tracking-tightest uppercase leading-none">
            {event.title}
          </h2>
          <p className="text-muted text-base md:text-lg mt-2 font-medium">
            {event.subtitle}
          </p>
        </div>

        {/* Summary */}
        <p className="text-muted/90 leading-relaxed text-sm md:text-base max-w-lg">
          {event.summary}
        </p>

        {/* Body */}
        {event.body && (
          <p className="text-muted/70 text-sm leading-relaxed max-w-lg border-l-2 border-accent/20 pl-4">
            {event.body}
          </p>
        )}

        {/* Achievements */}
        {event.achievements && event.achievements.length > 0 && (
          <ul className="space-y-2 pt-2">
            {event.achievements.map((a, i) => (
              <li key={i} className="flex items-start gap-3 text-sm text-muted/80">
                <span className="mt-1.5 w-1.5 h-1.5 rounded-full bg-accent/50 flex-shrink-0" />
                {a}
              </li>
            ))}
          </ul>
        )}

        {/* Image thumbnails */}
        {event.images.length > 0 && (
          <div className="flex gap-2 pt-4 overflow-x-auto">
            {event.images.map((img) => (
              <div
                key={img.id}
                className="w-16 h-16 md:w-20 md:h-20 rounded-sm bg-background-layer2 border border-white/5 overflow-hidden flex-shrink-0"
              >
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img
                  src={img.src}
                  alt={img.alt}
                  className="w-full h-full object-cover opacity-60"
                  loading="lazy"
                />
              </div>
            ))}
          </div>
        )}
      </div>
    </motion.article>
  );
}
